import socket
import json

class GameServer:
    def __init__(self):
        self.clients = {}
        self.game_state = {}

    def handle_client(self, client_socket):
        client_id = len(self.clients) + 1
        self.clients[client_id] = Client(client_socket)
        print(f"New client connected with id {client_id}")

    def handle_client_disconnect(self, client_id):
        del self.clients[client_id]
        print(f"Client disconnected with id {client_id}")

    def update_game_state(self, new_game_state):
        self.game_state = new_game_state

    def broadcast_game_state(self):
        for client in self.clients:
            self.send_data(client, self.game_state)

class Client:
    def __init__(self, socket):
        self.socket = socket

    def send_data(self, data):
        json_data = json.dumps(data).encode()
        self.socket.sendall(json_data)